358	
359	// PushObjects pushes locally-materialized objects to the target.
360	//
361	// Delta selection runs synchronously up front via
362	// packfile.DeltaSelector. The selected objects are then handed back to
363	// a packfile.Encoder behind a passthrough ObjectSelector, so the
364	// encoder's write phase (Encode → encode(objects)) streams pack bytes
365	// continuously into an io.Pipe to the HTTP request body. This avoids
366	// the mid-stream stall that occurs when Encode runs selection itself —
367	// CDN edges treat the resulting idle gap as a stalled upload and close
368	// the connection. See go-git PR #2142 for the API hook.
369	func PushObjects(
370		ctx context.Context,
371		conn Conn,
372		adv *packp.AdvRefs,
373		commands []PushCommand,
374		store storer.Storer,
375		hashes []plumbing.Hash,
376		verbose bool,
377		onRejection func(plumbing.ReferenceName, string),
378	) error {
379		req, _, hasUpdates, err := buildUpdateRequest(adv, commands, verbose)
380		if err != nil {
381			return err
382		}
383		if !hasUpdates {
384			return sendReceivePack(ctx, conn, req, nil, verbose, onRejection)
385		}
386	
387		progressDest := progressSink(verbose, "target: ", conn.ProgressWriter())
388	
389		stopSelect := startSelectionProgress(progressDest)
390		objects, err := packfile.NewDeltaSelector(store).ObjectsToPack(hashes, 10)
391		stopSelect(len(objects), err)
392		if err != nil {
393			return fmt.Errorf("select objects to pack: %w", err)
394		}
395	
396		useRefDeltas := !adv.Capabilities.Supports(capability.OFSDelta)
397		pr, pw := io.Pipe()
398		done := make(chan error, 1)
399		go func() {
400			cw := &countingWriter{w: pw}
401			stopWrite := startPackWriteProgress(cw, progressDest)
402			defer stopWrite()
403			enc := packfile.NewEncoder(cw, store, useRefDeltas,
404				packfile.WithObjectSelector(precomputedSelector{objects: objects}))
405			if _, err := enc.Encode(hashes, 10); err != nil {
406				done <- pw.CloseWithError(fmt.Errorf("encode packfile: %w", err))
407				return
408			}
409			done <- pw.Close()
410		}()
411	
412		err = sendReceivePack(ctx, conn, req, pr, verbose, onRejection)
413		_ = pr.Close()
414		encodeErr := <-done
415		if err != nil {
416			return err
417		}
418		return encodeErr
419	}
420	
421	// precomputedSelector is a packfile.ObjectSelector that returns a
422	// fixed []*packfile.ObjectToPack, ignoring its arguments. It is the
423	// passthrough used by PushObjects to feed pre-selected objects back
424	// into packfile.Encoder via WithObjectSelector. Used exactly once per
425	// PushObjects call and not exposed outside this package.
426	type precomputedSelector struct {
427		objects []*packfile.ObjectToPack
428	}
429	
430	func (p precomputedSelector) ObjectsToPack(_ []plumbing.Hash, _ uint) ([]*packfile.ObjectToPack, error) {
431		return p.objects, nil
432	}
433	
434	// countingWriter wraps an io.Writer and tracks total bytes written.
435	// The count is read by the progress ticker concurrently with the
436	// encoder's writes, so the counter is atomic.
437	type countingWriter struct {
438		w io.Writer
439		n atomic.Int64
440	}
441	
442	func (cw *countingWriter) Write(p []byte) (int, error) {
443		n, err := cw.w.Write(p)
444		cw.n.Add(int64(n))
445		if err != nil {
446			return n, fmt.Errorf("counting writer: %w", err)
447		}
448		return n, nil
449	}
450	
451	func (cw *countingWriter) Count() int64 { return cw.n.Load() }
452	
453	// startSelectionProgress emits in-place "selecting deltas, elapsed X"
454	// updates every 500ms during the synchronous delta-selection phase of
455	// PushObjects. The returned stop function takes the number of selected
456	// objects and the selection error (nil on success); on success it
457	// finalizes the line with a permanent "selected N objects in Y"
458	// summary, on error it just stops the ticker without claiming success.
459	// When dest is nil (non-verbose mode) returns a no-op stop, so
460	// callers don't need to special-case verbosity.
461	//
462	// Selection has no observable byte progress — go-git's DeltaSelector
463	// is opaque to the caller — so elapsed time is the only signal we can
464	// surface to keep long selections from looking like a hang.
465	func startSelectionProgress(dest io.Writer) func(objectCount int, err error) {
466		if dest == nil {
467			return func(int, error) {}
468		}
