package diss

import (
	"bytes"
	"context"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"sync/atomic"

	"github.com/go-git/go-git/v6/plumbing"

	pb "entire.io/gen/proto/internalapi/diss/v1"
	"entire.io/gitutil"
	"entire.io/objstore"
	"entire.io/objstore/fsck"
	"entire.io/otel"
	"entire.io/packfile"
	"entire.io/slogutil"
)

// StorePackfileWithConnectivityCheck stages the packfile on every provider,
// optionally runs a connectivity check against the proposed ref tips in
// parallel with the remaining stage acks, then commits the pack on all
// providers if everything passed (or discards it on any failure).
//
// Pass tips=nil to skip the connectivity check entirely — the function still
// fans the pack out and waits for quorum, just without verifying object
// reachability. This is the path used by go-git internals writing packs
// through Storage.PackfileWriter.
//
// Returns per-ref connectivity errors when the check rejected one or more
// refs (the pack is also discarded everywhere in that case). The caller
// (receive-pack) emits these as `ng <ref> <reason>` report-status lines.
//
// Empty packs (zero objects declared in the pack header) skip the fanout
// entirely and only verify proposed tips exist in canonical storage —
// equivalent to a ref-only push.
//
// Lives in diss rather than objstore because the local-provider branch
// calls entire.io/objstore/fsck and entire.io/gitutil directly, both of
// which already import entire.io/objstore.
func StorePackfileWithConnectivityCheck(
	ctx context.Context,
	storer objstore.Storer,
	rd io.Reader,
	declaredSize int64,
	tips []*pb.ProposedTip,
	onProgress func(objstore.PackfileProgress),
) (map[plumbing.ReferenceName]error, error) {
	ctx, span := otel.Tracer().Start(ctx, "diss.StorePackfileWithConnectivityCheck")
	defer span.End()

	qs, ok := storer.(objstore.QuarantinedPushStorer)
	if !ok {
		return nil, errors.New("storer does not support quarantined push")
	}

	// Empty packs (e.g. pushing a ref pointer to an already-known commit)
	// carry only the 12-byte header + 20-byte trailer. Quarantine staging
	// would fail because gitpack.Index produces an .idx the mmap loader
	// rejects as too short, so peek the header and skip fanout + commit
	// when there are no objects — just verify the proposed tips exist.
	rd, numObjects, err := peekPackObjectCount(rd)
	if err != nil {
		return nil, err
	}
	if numObjects == 0 {
		return emptyPackConnectivityCheck(ctx, storer, rd, tips)
	}

	checkCtx, cancelCheck := context.WithCancel(ctx)
	defer cancelCheck()

	// checkCh is buffered(1) and the goroutine sends exactly once, so any
	// abort path that calls awaitCheck after cancelCheck is guaranteed to
	// observe the goroutine's exit — required because Abort/Commit will
	// Discard the local Quarantined's mmap, which the check goroutine is
	// reading via .idx lookups.
	//
	// signalFirstAck invokes onFirstAck synchronously, so checkStarted is
	// published before the provider goroutine exits. After wg.Wait() in
	// the fanout returns, awaitCheck reads a reliable value.
	var checkStarted atomic.Bool
	checkCh := make(chan checkOutcome, 1)
	wantCheck := len(tips) > 0
	onFirstAck := func(ack *objstore.ProviderAck) {
		if !wantCheck {
			return
		}
		checkStarted.Store(true)
		go func() {
			var resp *pb.ConnectivityCheckResponse
			var err error
			if ack.IsLocal {
				resp, err = runLocalConnectivityCheck(checkCtx, storer, ack, tips)
			} else {
				resp, err = qs.ConnectivityCheckOnProvider(checkCtx, ack, tips)
			}
			checkCh <- checkOutcome{resp: resp, err: err}
		}()
	}
	awaitCheck := func() (checkOutcome, bool) {
		if !checkStarted.Load() {
			return checkOutcome{}, false
		}
		return <-checkCh, true
	}

	result, err := qs.StorePackfileQuarantine(ctx, rd, declaredSize, onProgress, onFirstAck)
	if err != nil {
		cancelCheck()
		_, _ = awaitCheck()
		return nil, fmt.Errorf("store packfile: %w", err)
	}

	abort := func() {
		cancelCheck()
		_, _ = awaitCheck()
		if abortErr := qs.AbortQuarantinedFanout(context.Background(), result); abortErr != nil {
			slogutil.Warn(ctx, "store-with-check: abort quarantine fanout failed",
				slog.Any("error", abortErr))
		}
	}

	if result.Quorum != nil {
		abort()
		return nil, result.Quorum
	}
	if result.FirstAcked() == nil {
		abort()
		return nil, errors.New("connectivity check: no provider acked the pack")
	}

	var connectivityErrors map[plumbing.ReferenceName]error
	if wantCheck {
		outcome, _ := awaitCheck()
		if outcome.err != nil {
			if abortErr := qs.AbortQuarantinedFanout(context.Background(), result); abortErr != nil {
				slogutil.Warn(ctx, "store-with-check: abort quarantine fanout failed",
					slog.Any("error", abortErr))
			}
			return nil, fmt.Errorf("connectivity check: %w", outcome.err)
		}
		connectivityErrors = buildConnectivityErrors(outcome.resp)
		if len(connectivityErrors) > 0 {
			slogutil.Warn(ctx, "store-with-check: connectivity check rejected refs",
				slog.Int("rejected_refs", len(connectivityErrors)))
		}
	}

	// Promoted packs (>= packfile.Threshold objects — the same deterministic
	// decision every provider's CommitPack makes) get appended as an
	// incremental MIDX layer per push. The walk tips ride in the commit
	// itself, filtered to refs that passed the connectivity check — exactly
	// the set the caller is about to CAS, passed explicitly so the append
	// never re-reads refs (TOCTTOU-free). Sub-threshold packs loose-ingest;
	// nothing to append.
	var appendTips []plumbing.Hash
	if numObjects >= packfile.Threshold {
		appendTips = appendTipsFromProposed(tips, connectivityErrors)
	}

	// CommitQuarantinedFanout returns *QuorumError iff commit-time providers
	// can't meet quorum (e.g. churn between stage and commit). Treat as fatal
	// so refs don't point to data that landed on a single node. The
	// successful commits leave orphan packs that existing GC reclaims.
	//
	// We commit even when some refs failed connectivity: the pack is well-
	// formed and may carry objects shared with refs that did pass. Per-ref
	// errors in the return surface the failing refs; the caller rejects only
	// those and lets the rest CAS-update.
	if commitErr := qs.CommitQuarantinedFanout(ctx, result, appendTips); commitErr != nil {
		return nil, fmt.Errorf("commit quorum: %w", commitErr)
	}

	// Remote providers self-trigger their append from the CommitPack
	// handler; the local provider committed in-process, so trigger it here.
	if len(appendTips) > 0 && result.HasLocalProvider() {
		if lsp, ok := storer.(objstore.LocalStorageProvider); ok {
			appendPromotedPack(lsp.LocalStorage(), storer.RepoID(), appendTips)
		}
	}
	return connectivityErrors, nil
}

// appendTipsFromProposed converts the proposed ref tips into bitmap walk
// tips for the post-promote MIDX append, dropping refs that failed the
// connectivity check — they won't CAS, so accelerating them would index
// unreachable history.
func appendTipsFromProposed(tips []*pb.ProposedTip, connectivityErrors map[plumbing.ReferenceName]error) []plumbing.Hash {
	out := make([]plumbing.Hash, 0, len(tips))
	for _, t := range tips {
		if _, failed := connectivityErrors[plumbing.ReferenceName(t.GetRefName())]; failed {
			continue
		}
		if h, ok := plumbing.FromBytes(t.GetHash()); ok {
			out = append(out, h)
		}
	}
	return out
}

// emptyPackConnectivityCheck handles a push whose pack reports zero objects:
// drain the reader (the wire bytes still arrived), then verify the proposed
// tips exist in canonical storage. No fanout, no commit, no abort.
func emptyPackConnectivityCheck(
	ctx context.Context,
	storer objstore.Storer,
	rd io.Reader,
	tips []*pb.ProposedTip,
) (map[plumbing.ReferenceName]error, error) {
	if _, err := io.Copy(io.Discard, rd); err != nil {
		return nil, fmt.Errorf("drain empty pack: %w", err)
	}
	if len(tips) == 0 {
		return nil, nil //nolint:nilnil // nil map signals "no per-ref errors"; success path
	}
	resp, err := runConnectivityCheck(ctx, storer, tips, nil)
	if err != nil {
		return nil, fmt.Errorf("empty-pack connectivity check: %w", err)
	}
	if len(resp.GetMissingByRef()) == 0 {
		return nil, nil //nolint:nilnil // nil map signals "no per-ref errors"; success path
	}
	return buildConnectivityErrors(resp), nil
}

// runLocalConnectivityCheck unwraps ack.Local into extras and delegates to
// runConnectivityCheck. Used by the in-process branch of the orchestrator
// when the local node is among the K-closest replicas.
func runLocalConnectivityCheck(
	ctx context.Context,
	storer objstore.Storer,
	ack *objstore.ProviderAck,
	tips []*pb.ProposedTip,
) (*pb.ConnectivityCheckResponse, error) {
	if storer == nil {
		return nil, errors.New("local connectivity check: no Storer")
	}
	var extras []*packfile.Loaded
	if ack.Local != nil {
		extras = []*packfile.Loaded{ack.Local.AsLoaded()}
	}
	return runConnectivityCheck(ctx, storer, tips, extras)
}

// runConnectivityCheck walks the object graph reachable from tips, treating
// extras as authoritative for objects not yet committed (a quarantined pack
// — either local or just opened on the receiver). Canonical lookups go
// through the storer, so for DissStore-backed storers the walk consults
// every K-closest provider for the repo, not just the local node. Bitmap-
// accelerated when a MIDX bitmap is loaded locally.
//
// Shared by the gRPC handler (packfileHandler.ConnectivityCheck) and the
// orchestrator's local branch.
func runConnectivityCheck(
	ctx context.Context,
	storer objstore.Storer,
	tips []*pb.ProposedTip,
	extras []*packfile.Loaded,
) (*pb.ConnectivityCheckResponse, error) {
	fsckTips := make([]fsck.ProposedTip, 0, len(tips))
	for i, t := range tips {
		h, ok := plumbing.FromBytes(t.GetHash())
		if !ok {
			return nil, fmt.Errorf("tip[%d] hash must be a SHA-1, got %d bytes", i, len(t.GetHash()))
		}
		if h.IsZero() {
			continue
		}
		fsckTips = append(fsckTips, fsck.ProposedTip{
			Name: plumbing.ReferenceName(t.GetRefName()),
			Hash: h,
		})
	}

	// Bitmap reflects pre-push ref tips, so it short-circuits only subgraphs
	// already reachable from existing refs — the common fast-forward case.
	// The bitmap is local-disk; skipping is therefore an optimization, not a
	// correctness boundary.
	rp := gitutil.LoadRepoPacker(ctx, storer)
	if rp != nil {
		defer rp.Close()
	}

	reader := objstore.NewConnectivityReader(storer, extras)
	result, err := fsck.CheckProposedTipsWithReader(ctx, reader, fsckTips, fsck.BitmapPruner(rp))
	if err != nil {
		return nil, fmt.Errorf("fsck.CheckProposedTipsWithReader: %w", err)
	}

	resp := &pb.ConnectivityCheckResponse{DurationNanos: result.Duration.Nanoseconds()}
	for refName, missing := range result.MissingByRef {
		if len(missing) == 0 {
			continue
		}
		per := &pb.PerRefMissing{
			RefName: string(refName),
			Missing: make([]*pb.MissingObject, len(missing)),
		}
		for i, m := range missing {
			per.Missing[i] = &pb.MissingObject{
				Hash: m.Hash.Bytes(),
				Type: uint32(m.Type), //nolint:gosec // ObjectType is a small enum
			}
		}
		resp.MissingByRef = append(resp.MissingByRef, per)
	}
	return resp, nil
}

// checkOutcome carries the result of an in-flight connectivity check so the
// orchestrator can await it after fanout completes.
type checkOutcome struct {
	resp *pb.ConnectivityCheckResponse
	err  error
}

// peekPackObjectCount reads the 12-byte pack header off rd and returns a
// new reader with those bytes pushed back, along with the declared object
// count. Used to detect empty packs before committing to the quarantine
// pipeline.
func peekPackObjectCount(rd io.Reader) (io.Reader, uint32, error) {
	var hdr [12]byte
	if _, err := io.ReadFull(rd, hdr[:]); err != nil {
		return rd, 0, fmt.Errorf("read packfile header: %w", err)
	}
	n, err := packfile.ParseHeader(hdr)
	if err != nil {
		return rd, 0, fmt.Errorf("parse packfile header: %w", err)
	}
	return io.MultiReader(bytes.NewReader(hdr[:]), rd), n, nil
}

// buildConnectivityErrors flattens a ConnectivityCheckResponse into per-ref
// errors suitable for receive-pack's `ng <ref> <reason>` report-status lines.
// Only the first missing object per ref is surfaced — git's report-status
// convention is one reason per ref.
func buildConnectivityErrors(resp *pb.ConnectivityCheckResponse) map[plumbing.ReferenceName]error {
	errs := make(map[plumbing.ReferenceName]error, len(resp.GetMissingByRef()))
	for _, per := range resp.GetMissingByRef() {
		if len(per.GetMissing()) == 0 {
			continue
		}
		first := per.GetMissing()[0]
		hash, _ := plumbing.FromBytes(first.GetHash())
		errs[plumbing.ReferenceName(per.GetRefName())] = fmt.Errorf(
			"missing %s %s", objectTypeLabel(first.GetType()), hash)
	}
	return errs
}

func objectTypeLabel(t uint32) string {
	ot := plumbing.ObjectType(int8(t)) //nolint:gosec // ObjectType is a small enum
	switch ot {                        //nolint:exhaustive // only real types are surfaced; default catches the rest
	case plumbing.CommitObject, plumbing.TreeObject, plumbing.BlobObject, plumbing.TagObject:
		return ot.String()
	default:
		return "object"
	}
}

